mapper.select:
select t.id, t.title, substring(trim(t.content), 1, 40) as summary, t.priority, t.status, t.assignee_student_id as assigneeStudentId, ua.real_name as assigneeName, t.creator_student_id as creatorStudentId, uc.real_name as creatorName, t.due_time as dueTime, t.create_time as createTime, case when t.due_time is not null and t.status in (0, 1) and t.due_time < #{query.now} then 1 else 0 end as overdue from dm_todo t left join user_student ua on ua.id = t.assignee_student_id and ua.delflag = 0 left join user_student uc on uc.id = t.creator_student_id and uc.delflag = 0 where t.delflag = 0 and t.room_id = #{query.roomId}
and (t.title like concat('%', #{query.keywords}, '%') or t.content like concat('%', #{query.keywords}, '%'))
and t.status = #{query.state}
and t.priority = #{query.priority}
and t.assignee_student_id = #{query.assigneeStudentId}
and t.due_time is not null and date(t.due_time) = current_date()
and t.due_time is not null and t.due_time >= #{query.now} and t.due_time < date_add(#{query.now}, interval 3 day)
and t.due_time is not null and t.status in (0, 1) and t.due_time < #{query.now}
order by case when t.status in (0, 1) then 0 else 1 end, t.priority desc, case when t.due_time is null then 1 else 0 end, t.due_time asc, t.create_time desc

select count(1)
from room_student
where room_id = #{roomId}
  and student_id = #{studentId}
  and is_current = 1
